// package-lock.json generation script

const fs = require('fs');
const path = require('path');

function generatePackageLock() {
  // Generate package-lock.json from package.json
  const packageJsonPath = path.join(process.cwd(), 'package.json');
  const packageLockJsonPath = path.join(process.cwd(), 'package-lock.json');

  if (fs.existsSync(packageLockJsonPath)) {
    console.log('Updating package-lock.json...');
  } else {
    console.log('Generating initial package-lock.json...');
  }

  try {
    const packageData = require(packageJsonPath);
    fs.writeFileSync(
      packageLockJsonPath,
      JSON.stringify({ devDependencies: packageData.devDependencies }, null, 2)
    );
    console.log('package-lock.json generated/updated successfully.');
  } catch (error) {
    console.error('Error generating/ updating package-lock.json:', error);
  }
}

// Example usage
generatePackageLock();